        let diff = ConfigDiff {
            lines: vec![DiffLine::Removed("r".into()), DiffLine::Added("a".into())],
        };
        assert_eq!(diff.peak_kind_count(), 1);
        assert_eq!(diff.peak_kind_multiplicity(), 2);
