        let diff = ConfigDiff {
            lines: vec![DiffLine::Added("a1".into()), DiffLine::Added("a2".into())],
        };
        assert_eq!(diff.present_kinds().len(), 1);
        assert!(diff.kinds_singular_support());
        assert!(!diff.kinds_strict_partial_cover());
