    #[test]
    fn kinds_antimodally_tied_collapses_with_kinds_modally_tied_on_uniform_multi_cell_diffs_pointwise()
     {
        // Modal / antimodal collapse pin: on every uniform-count
        // multi-cell diff the two tie predicates read the same value.
        // Direct pin of the histogram-side collapse law
        // `is_uniform_count ∧ !is_empty ⇒ is_antimodally_tied ⇔
        // is_modally_tied` one altitude down, at the diff altitude.
        // On the singleton-support uniform corner both read `false`;
        // on every multi-cell uniform diff both read `true`.
        for diff in dominant_kind_fixtures() {
            if diff.kinds_balanced() && diff.kinds_any_observed() {
                assert_eq!(
                    diff.kinds_antimodally_tied(),
                    diff.kinds_modally_tied(),
                    "on a uniform-count non-empty diff the two tie \
                     predicates must collapse to the same value",
                );
            }
        }
    }

    #[test]
    fn kinds_antimodally_tied_agrees_with_open_coded_trough_multiplicity_walk() {
        // Parity against the exact hand-rolled trough-multiplicity
        // walk this lift replaces: walk every cell of the histogram
        // and count how many carry the strictly-positive minimum
        // observed count; the antimodally-tied predicate reads `true`
        // iff the multiplicity is at least `2`. Empty histogram has
        // no strictly-positive counts, so multiplicity reads `0` and
        // the predicate fails.
        for diff in dominant_kind_fixtures() {
            let via_seam = diff.kinds_antimodally_tied();
            let hist = diff.kind_histogram();
            let min = hist
                .iter()
                .map(|(_, c)| c)
                .filter(|c| *c > 0)
                .min()
                .unwrap_or(0);
            let hand_rolled = if min == 0 {
                false
            } else {
                hist.iter().filter(|(_, c)| *c == min).count() >= 2
            };
            assert_eq!(via_seam, hand_rolled);
        }
    }

